CREATE INDEX IF NOT EXISTS "IX_TherapeuticPlans_TenantId" ON "TherapeuticPlans" ("TenantId");
"""); if (!seedDemo) return; var tenant = await db.Tenants.IgnoreQueryFilters().SingleOrDefaultAsync(x => x.Slug == "demo"); if (tenant is null) { tenant = new Tenant { Name = "Clínica Ello", Slug = "demo", Email = "contato@elloclinic.com.br" }; db.Tenants.Add(tenant); await db.SaveChangesAsync(); db.Users.Add(new AppUser { TenantId = tenant.Id, Name = "Administrador", Email = "admin@ello.local", PasswordHash = Passwords.Hash("Ello@123"), Role = UserRole.ClinicAdmin }); await db.SaveChangesAsync(); } var professional = await db.Professionals.IgnoreQueryFilters().Where(x => x.TenantId == tenant.Id && x.Email == "mariana@ello.local").OrderBy(x => x.CreatedAt).FirstOrDefaultAsync(); if (professional is not null && !await db.Users.IgnoreQueryFilters().AnyAsync(x => x.TenantId == tenant.Id && x.Email == "mariana@ello.local")) { db.Users.Add(new AppUser { TenantId = tenant.Id, ProfessionalId = professional.Id, Name = professional.Name, Email = "mariana@ello.local", PasswordHash = Passwords.Hash("Mariana@123"), Role = UserRole.Professional }); await db.SaveChangesAsync(); } }
